public void testAvailableLocaleSet() {

    Set set = LocaleUtils.availableLocaleSet();

    Set set2 = LocaleUtils.availableLocaleSet();

    assertNotNull(set);

    assertSame(set, set2);

    assertUnmodifiableCollection(set);



